from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # Group triples by their subject to allow richer combined phrasing
    by_subject: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        by_subject.setdefault(t.subject, []).append((t.predicate, t.object))

    sentences: list[str] = []

    for subj, preds in by_subject.items():
        # Collect information for this subject
        info: dict[str, list[str]] = {}
        for p, o in preds:
            info.setdefault(p, []).append(o)

        parts: list[str] = []

        # Basic identity (nationality, birthPlace, birthDate/Year)
        if "nationality" in info:
            nat = ", ".join(info["nationality"])
            parts.append(f"{subj} is {nat}")
        if "birthPlace" in info:
            places = ", ".join(info["birthPlace"])
            parts.append(f"{subj} was born in {places}")
        if "birthDate" in info:
            dates = ", ".join(info["birthDate"])
            parts.append(f"{subj} was born on {dates}")
        elif "birthYear" in info:
            years = ", ".join(info["birthYear"])
            parts.append(f"{subj} was born in {years}")

        # Occupation / role
        if "occupation" in info:
            occs = ", ".join(o.lower() for o in info["occupation"])
            parts.append(f"{subj} is a {occs}")

        # Musical specifics
        if "genre" in info:
            genres = ", ".join(info["genre"])
            parts.append(f"{subj} performs {genres} music")
        if "instrument" in info:
            instrs = ", ".join(info["instrument"])
            parts.append(f"{subj} plays {instrs}")
        if "associatedBand/associatedMusicalArtist" in info:
            bands = ", ".join(info["associatedBand/associatedMusicalArtist"])
            parts.append(f"{subj} is associated with {bands}")
        if "recordLabel" in info:
            labs = ", ".join(info["recordLabel"])
            parts.append(f"{subj} is signed to {labs}")

        # Active years (combine start and end when both exist)
        start = info.get("activeYearsStartYear", [])
        end = info.get("activeYearsEndYear", [])
        if start and end:
            parts.append(f"{subj} was active from {start[0]} to {end[0]}")
        elif start:
            parts.append(f"{subj} started their career in {start[0]}")
        elif end:
            parts.append(f"{subj} ended their career in {end[0]}")

        # Origin / location related predicates
        if "origin" in info:
            origins = ", ".join(info["origin"])
            parts.append(f"{subj} originates from {origins}")
        if "country" in info:
            countries = ", ".join(info["country"])
            parts.append(f"{subj} is in the country of {countries}")
        if "isPartOf" in info:
            parts.append(f"{subj} is part of {info['isPartOf'][0]}")
        if "capital" in info:
            parts.append(f"The capital of {subj} is {info['capital'][0]}")
        if "language" in info or "officialLanguage" in info:
            langs = info.get("language", []) + info.get("officialLanguage", [])
            parts.append(f"The language of {subj} is {', '.join(langs)}")
        if "deathPlace" in info:
            parts.append(f"{subj} died in {info['deathPlace'][0]}")
        if "deathDate" in info:
            parts.append(f"{subj} died on {info['deathDate'][0]}")

        # Fallback for any unhandled predicates
        handled = {
            "nationality","birthPlace","birthDate","birthYear","occupation","genre",
            "instrument","associatedBand/associatedMusicalArtist","recordLabel",
            "activeYearsStartYear","activeYearsEndYear","origin","country","isPartOf",
            "capital","language","officialLanguage","deathPlace","deathDate"
        }
        for p, objs in preds:
            if p not in handled:
                for o in objs:
                    parts.append(f"{subj} {p} {o}")

        # Combine parts for this subject
        if parts:
            sentence = "; ".join(parts) + "."
            sentences.append(sentence)

    # Join multiple subject sentences with a space
    return " ".join(sentences)

# EVOLVE-BLOCK-END

